async function boot(){guide=await fetch('content.json').then(r=>r.json());renderNav();renderHome();bindGlobal()}
function renderNav(){const items=[['home','홈'],...Object.entries(meta).map(([k,v])=>[k,v.name]),['dictionary','용어']];for(const id of ['primaryNav','mobileNav'])$( '#'+id).innerHTML=items.map(([k,n])=>`<button data-view="${k}" class="${view===k?'active':''}">${n}</button>`).join('')}
function go(next){view=next;renderNav();next==='home'?renderHome():next==='dictionary'?renderDictionary():renderTopic(next);window.scrollTo({top:0,behavior:'instant'})}
function renderHome(){$('#app').innerHTML=`<div class="home-page"><main class="home-console"><header class="home-console-head"><div><p class="eyebrow">FINANCE FIELDBOOK · v${guide.version}</p><h1>학습 대시보드</h1></div><button class="home-search" id="homeSearch" type="button">용어 검색 <span>⌕</span></button></header><section class="home-metrics"><article class="home-metric live"><small>MARKET SNAPSHOT</small><strong id="kospi">KOSPI 불러오는 중</strong><span id="marketTime">지연 또는 실패 시 KRX 링크 제공</span></article><article class="home-metric"><small>KNOWLEDGE MAP</small><strong>4개 분야</strong><span>핵심 프레임 → 심화 단원</span></article><article class="home-metric"><small>INTERACTIVE LABS</small><strong>6개+</strong><span>경제 · 투자 · 설계 · 법률</span></article></section><section class="home-workspace"><div class="home-section"><div class="home-section-head"><h2>분야 선택</h2><span>원하는 주제에서 바로 시작</span></div><div class="home-field-grid">${Object.entries(meta).map(([key,item],index)=>`<button class="home-field" data-view="${key}"><span>0${index+1}</span><b>${item.name}</b><small>${item.bullets[0]}</small><i>→</i></button>`).join('')}</div></div><aside class="home-shortcuts"><div class="home-section-head"><h2>바로가기</h2><span>실습 도구</span></div><button data-view="01_economics"><b>AD–AS 충격 실험</b><small>수요·공급 충격 비교</small></button><button data-view="02_finance"><b>채권 · DCF 민감도</b><small>가격·할인율 직접 계산</small></button><button data-view="03_planning"><b>세후 수익 · 안전판</b><small>현금흐름 우선순위 점검</small></button><button data-view="04_law"><b>판매의무 판단</b><small>권유 단계별 통제 확인</small></button></aside></section></main></div>`;$('#homeSearch').onclick=()=>$('#searchButton').click();loadMarket()}
