function atlasPanel(tab){return `<div class="atlas-panel"><h3>${tab.title}</h3><p>${tab.lead}</p><div class="atlas-card-grid">${tab.cards.map(card=>`<article><span>${card[0]}</span><strong>${card[1]}</strong></article>`).join('')}</div></div>`}
function renderExpertAtlas(slug){const atlas=expertAtlas[slug];if(!atlas)return'';return `<section class="expert-atlas" data-atlas="${slug}"><div class="atlas-head"><p class="eyebrow">${atlas.label}</p><h2>${atlas.title}</h2><p>${atlas.summary}</p></div><div class="atlas-flow">${atlas.flow.map((item,index)=>`<div class="atlas-node"><span>${String(index+1).padStart(2,'0')}</span><b>${item}</b></div>`).join('')}</div><div class="atlas-tabs">${atlas.tabs.map((tab,index)=>`<button type="button" data-atlas-tab="${tab.key}" class="${index===0?'active':''}">${tab.label}</button>`).join('')}</div><div data-atlas-panel>${atlasPanel(atlas.tabs[0])}</div><div class="atlas-sources"><span>보강 근거</span>${atlas.sources.map(source=>`<a href="${source[1]}" target="_blank" rel="noreferrer">${source[0]} ↗</a>`).join('')}<small>법령·세제·시장제도는 사용 전 원문과 시행일을 다시 확인하세요.</small></div></section>`}
function bindAtlas(){document.querySelectorAll('[data-atlas]').forEach(host=>{const atlas=expertAtlas[host.dataset.atlas];host.querySelectorAll('[data-atlas-tab]').forEach(button=>button.addEventListener('click',()=>{host.querySelectorAll('[data-atlas-tab]').forEach(item=>item.classList.toggle('active',item===button));const tab=atlas.tabs.find(item=>item.key===button.dataset.atlasTab);host.querySelector('[data-atlas-panel]').innerHTML=atlasPanel(tab)}))})}
const learningBlueprint={
  '01_economics':{question:'지표 변화가 경기·금리·환율·자산가격에 어떤 순서로 전달되는가?',lenses:[['판독 순서','수준 → 증가율 → 갭 → 충격의 원인'],['연결 변수','성장·물가·고용·신용·환율을 함께 확인'],['설명 장면','FOMC·금통위·환율 변동을 투자 논리로 설명']]},
  '02_finance':{question:'이 상품의 현금흐름과 위험은 무엇이며, 가격은 어떤 가정에 민감한가?',lenses:[['분석 순서','현금흐름 → 할인율 → 위험 → 가격 → 포지션'],['핵심 구분','채권·주식·파생·대안투자의 손익 구조 분리'],['설명 장면','상품 비교, 기업가치 평가, 포트폴리오 점검']]},
  '03_planning':{question:'목표와 제약조건을 반영한 세후·실질 기준의 실행안은 무엇인가?',lenses:[['설계 순서','현황 → 목표 → 현금흐름 → 위험관리 → 실행·점검'],['핵심 구분','세전/세후, 명목/실질, 유동성/장기자금'],['설명 장면','은퇴·보험·계좌·상속증여 의사결정']]},
  '04_law':{question:'누가, 어떤 상품을, 어떤 정보로, 언제 어떻게 권유·거래했는가?',lenses:[['판단 순서','주체 → 행위 → 의무 → 증빙 → 책임'],['핵심 구분','적합성·적정성·설명의무와 불공정거래 분리'],['설명 장면','금융상품 권유, 분쟁예방, 윤리적 의사결정']]}
};
function renderLearningFrame(slug){const frame=learningBlueprint[slug];if(!frame)return'';return `<section class="learning-frame"><div class="frame-head"><p class="eyebrow">HOW TO READ THIS FIELD</p><h2>이 분야를 푸는 질문</h2><p>${frame.question}</p></div><div class="lens-grid">${frame.lenses.map((lens,index)=>`<article class="lens-card"><span>0${index+1}</span><h3>${lens[0]}</h3><p>${lens[1]}</p><small>${lens[2]||'심화 단원에서 원리·예외·계산 기준을 확인'}</small></article>`).join('')}</div></section>`}
let activeStudyDocument=null;
function parseStudyDocument(html){const doc=document.createElement('div');doc.innerHTML=html.replace(/<h1>.*?<\/h1>/,'');doc.querySelectorAll('table').forEach(table=>{const wrap=document.createElement('div');wrap.className='table-scroll';table.replaceWith(wrap);wrap.append(table)});const prelude=[],closing=[],groups=[];let group=null,unit=null,started=false;[...doc.children].forEach(node=>{const tag=node.tagName;if(tag==='H4'){started=true;group={title:node.textContent.trim(),units:[]};groups.push(group);unit=null;return}if(tag==='H5'){started=true;if(!group){group={title:'심화 학습',units:[]};groups.push(group)}unit={title:node.textContent.trim(),content:[]};group.units.push(unit);return}if((tag==='H2'||tag==='H3')&&started){unit=null;closing.push(node.outerHTML);return}if(unit){unit.content.push(node.outerHTML);return}(started?closing:prelude).push(node.outerHTML)});return{prelude,closing,groups}}
function renderModuleNavigation(doc){return `<div class="module-nav"><p class="aside-label">CONTENTS</p>${doc.groups.map((group,index)=>`<button class="${index===0?'active':''}" data-module-index="${index}"><span>${String(index+1).padStart(2,'0')}</span><b>${group.title}</b><small>${group.units.length}개 핵심 단원</small></button>`).join('')}${doc.closing.length?'<button data-module-index="summary"><span>Σ</span><b>핵심 요약</b><small>마무리 정리</small></button>':''}</div>`}
function renderModuleGroup(group,index){return `<section class="module-stage"><div class="module-stage-head"><span>CHAPTER ${String(index+1).padStart(2,'0')}</span><h2>${group.title}</h2><p>${group.units.length}개 핵심 개념 · 필요한 항목만 펼쳐 보세요.</p></div><div class="module-list">${group.units.map((unit,unitIndex)=>`<details class="module-item"><summary><span class="module-index">${String(unitIndex+1).padStart(2,'0')}</span><span class="module-title">${unit.title}</span><small>핵심 개념·기준 보기</small></summary><div class="module-content">${unit.content.join('')}</div></details>`).join('')}</div></section>`}
function renderStudyStage(index){if(index==='summary')return `<section class="closing-notes"><div class="section-kicker">RECAP</div>${activeStudyDocument.closing.join('')}</section>`;return renderModuleGroup(activeStudyDocument.groups[Number(index)],Number(index))}
function structureChapterHtml(html){activeStudyDocument=parseStudyDocument(html);const prelude=activeStudyDocument.prelude.length?`<section class="core-notes"><div class="section-kicker">CORE NOTES</div><div class="core-note-body">${activeStudyDocument.prelude.join('')}</div></section>`:'';return `${prelude}<div id="moduleStage">${renderStudyStage(0)}</div>`}
function bindStudyNavigation(){document.querySelectorAll('[data-module-index]').forEach(button=>button.onclick=()=>{const index=button.dataset.moduleIndex;document.querySelectorAll('[data-module-index]').forEach(item=>item.classList.toggle('active',item===button));$('#moduleStage').innerHTML=renderStudyStage(index);$('#moduleStage').scrollIntoView({behavior:'smooth',block:'start'})})}
function renderTopic(slug){const chapter=guide.chapters.find(c=>c.slug===slug),m=meta[slug],frame=learningBlueprint[slug],studyMarkup=structureChapterHtml(chapter.html);$('#app').innerHTML=`<div class="page topic-page"><header class="topic-head"><p class="eyebrow">${m.tag}</p><h1>${m.name}</h1><p>${m.desc}</p></header><div class="topic-layout"><aside class="topic-aside">${renderModuleNavigation(activeStudyDocument)}</aside><article><div class="expert-note"><strong>전문가의 판단 순서</strong>${m.note}</div>${special(slug)}${renderExpertAtlas(slug)}<div class="study-body" id="studyBody">${studyMarkup}</div><section class="tool-panel"><h3>검증 가능한 출처</h3><p>제도·세율·공시·통계처럼 바뀔 수 있는 정보는 아래 1차 출처에서 최종 확인합니다.</p><div class="source-list">${m.sources.map(s=>`<a href="${s[1]}" target="_blank" rel="noreferrer">${s[0]} ↗</a>`).join('')}</div></section></article></div></div>`;bindAtlas();bindTools(slug);bindStudyNavigation()}
function renderMacroLab(){return `<section class="tool-panel concept-lab"><div class="lab-title"><span>INTERACTIVE ECONOMICS LAB</span><h3>AD–AS 충격 실험</h3><p>충격을 선택해 산출·물가·정책의 관계를 비교하세요.</p></div><div class="lab-controls"><button class="active" data-macro="base">기준점</button><button data-macro="demand">총수요 확대</button><button data-macro="supply">총공급 악화</button></div><div class="macro-lab-grid"><svg class="macro-chart" viewBox="0 0 460 260" role="img" aria-label="총수요 총공급 곡선"><line x1="55" y1="20" x2="55" y2="220" class="axis"/><line x1="55" y1="220" x2="430" y2="220" class="axis"/><text x="22" y="30">P</text><text x="426" y="242">Y</text><path id="macroAd" d="M95 55 L405 195" class="curve demand"/><path id="macroAs" d="M125 198 L360 45" class="curve supply"/><circle id="macroEq" cx="254" cy="127" r="6" class="equilibrium"/><text id="macroLabel" x="266" y="120">E₀</text><text x="350" y="185">AD</text><text x="332" y="59">AS</text></svg><div id="macroOutcome" class="lab-outcome"><b>기준점</b><p>산출·물가·고용의 수준과 변화율을 함께 보고, 잠재산출 대비 위치는 여러 지표로 교차검증합니다.</p><ul><li>실질 GDP와 물가를 같은 시점 기준으로 확인</li><li>고용·임금·신용·환율을 함께 판독</li></ul></div></div><small class="lab-note">방향 이해를 위한 단순화 도식입니다. 실제 시차와 정책반응은 경제 여건에 따라 달라집니다.</small></section>`}
function bindMacroLab(){const states={base:{ad:'',as:'',xy:'254,127',tag:'E₀',title:'기준점',text:'산출·물가·고용의 수준과 변화율을 함께 보고, 잠재산출 대비 위치는 여러 지표로 교차검증합니다.',list:['실질 GDP와 물가를 같은 시점 기준으로 확인','고용·임금·신용·환율을 함께 판독']},demand:{ad:'translate(30 -12)',as:'',xy:'284,112',tag:'E₁',title:'총수요 확대',text:'총수요 증가는 단기적으로 산출과 물가를 함께 올릴 수 있습니다. 장기금리와 주가는 정책기대·위험선호를 함께 반영합니다.',list:['산출·고용·근원물가의 동행 여부 확인','기대인플레이션과 임금·서비스물가의 지속성 점검']},supply:{ad:'',as:'translate(-35 0)',xy:'225,108',tag:'E₂',title:'총공급 악화',text:'비용·병목·환율발 공급충격은 산출 둔화와 물가 상승을 동시에 만들어 정책의 상충관계를 키웁니다.',list:['헤드라인·근원·수입물가를 분리','성장 둔화와 인플레이션 압력을 동시에 평가']}};document.querySelectorAll('[data-macro]').forEach(button=>button.onclick=()=>{const s=states[button.dataset.macro];document.querySelectorAll('[data-macro]').forEach(x=>x.classList.toggle('active',x===button));$('#macroAd').setAttribute('transform',s.ad);$('#macroAs').setAttribute('transform',s.as);const [x,y]=s.xy.split(',');$('#macroEq').setAttribute('cx',x);$('#macroEq').setAttribute('cy',y);$('#macroLabel').setAttribute('x',Number(x)+12);$('#macroLabel').setAttribute('y',Number(y)-8);$('#macroLabel').textContent=s.tag;$('#macroOutcome').innerHTML=`<b>${s.title}</b><p>${s.text}</p><ul>${s.list.map(x=>`<li>${x}</li>`).join('')}</ul>`})}
function renderDcfLab(){return `<section class="tool-panel concept-lab"><div class="lab-title"><span>INTERACTIVE FINANCE LAB</span><h3>DCF 가정 민감도</h3><p>현금흐름·성장·할인율을 직접 바꿔 기업가치가 왜 민감한지 확인하세요.</p></div><div class="calculator"><label>초기 FCFF(백만원)<input id="dcfFcf" type="number" value="100" min="0" step="10"></label><label>5년 성장률(%)<input id="dcfGrowth" type="number" value="6" step="0.5"></label><label>WACC(%)<input id="dcfWacc" type="number" value="9" step="0.5"></label><label>영구성장률(%)<input id="dcfTerminal" type="number" value="3" step="0.25"></label><div class="result-box"><span>추정 기업가치(EV)</span><strong id="dcfResult">-</strong></div></div><small class="lab-note">5년 명시기간 FCFF와 말기가치의 단순 모형입니다. EV에서 순차입금·비영업자산·희석주식수를 별도 조정합니다.</small></section>`}
function bindDcfLab(){const update=()=>{const f=+$('#dcfFcf').value||0,g=(+$('#dcfGrowth').value||0)/100,w=(+$('#dcfWacc').value||0)/100,t=(+$('#dcfTerminal').value||0)/100;if(w<=t||w<=0){$('#dcfResult').textContent='WACC > 영구성장률 필요';return}let pv=0;for(let year=1;year<=5;year++)pv+=f*Math.pow(1+g,year)/Math.pow(1+w,year);const f5=f*Math.pow(1+g,5),tv=f5*(1+t)/(w-t),ev=pv+tv/Math.pow(1+w,5);$('#dcfResult').textContent=`${won(ev)}백만원`};['dcfFcf','dcfGrowth','dcfWacc','dcfTerminal'].forEach(id=>$('#'+id).oninput=update);update()}
function renderCashflowLab(){return `<section class="tool-panel concept-lab"><div class="lab-title"><span>INTERACTIVE PLANNING LAB</span><h3>현금흐름 안전판 점검</h3><p>수익률 계산보다 먼저 소득 공백을 버틸 유동성을 확인합니다.</p></div><div class="calculator"><label>유동성 자산(만원)<input id="bufferLiquid" type="number" value="1200" min="0" step="100"></label><label>필수 월지출(만원)<input id="bufferExpense" type="number" value="250" min="1" step="10"></label><label>목표 안전판(개월)<input id="bufferTarget" type="number" value="6" min="1" max="24" step="1"></label><div class="result-box"><span>현재 안전판</span><strong id="bufferResult">-</strong></div></div><p id="bufferMessage" class="lab-message"></p><small class="lab-note">교육용 우선순위 도구입니다. 소득 안정성·부양가족·보험보장·대출만기를 함께 고려하세요.</small></section>`}
function bindBufferLab(){const update=()=>{const liquid=+$('#bufferLiquid').value||0,expense=+$('#bufferExpense').value||1,target=+$('#bufferTarget').value||0,months=liquid/expense,gap=target-months;$('#bufferResult').textContent=`${months.toFixed(1)}개월`;$('#bufferMessage').textContent=gap<=0?`목표 ${target}개월을 충족합니다. 다음 우선순위는 고금리부채·보장·장기목표를 함께 점검하는 것입니다.`:`목표까지 ${gap.toFixed(1)}개월분이 부족합니다. 수익률 추구보다 유동성 확보 계획을 먼저 검토하세요.`};['bufferLiquid','bufferExpense','bufferTarget'].forEach(id=>$('#'+id).oninput=update);update()}
function renderConductLab(){return `<section class="tool-panel concept-lab"><div class="lab-title"><span>INTERACTIVE LAW & ETHICS LAB</span><h3>판매 단계별 의무 점검</h3><p>행위 유형을 고르면 먼저 확인할 통제 항목을 보여줍니다. 실제 적용은 상품·소비자·시행규정 원문을 확인해야 합니다.</p></div><div class="lab-controls"><button class="active" data-conduct="recommend">권유하는 경우</button><button data-conduct="nonrecommend">권유 없이 계약</button><button data-conduct="explain">계약·설명 단계</button></div><div id="conductOutcome" class="law-outcome"><b>권유하는 경우</b><ol><li>고객의 목적·재산·경험·위험선호 등 정보를 수집한다.</li><li>상품 위험과 고객 특성의 적합성을 판단하고 근거를 남긴다.</li><li>중요 위험·비용·손실 가능성을 설명하고 확인 절차를 갖춘다.</li></ol></div><small class="lab-note">적합성·적정성·설명의무는 적용 요건이 다릅니다. 이 도구는 학습용 절차도입니다.</small></section>`}
function bindConductLab(){const modes={recommend:{title:'권유하는 경우',items:['고객의 목적·재산·경험·위험선호 등 정보를 수집한다.','상품 위험과 고객 특성의 적합성을 판단하고 근거를 남긴다.','중요 위험·비용·손실 가능성을 설명하고 확인 절차를 갖춘다.']},nonrecommend:{title:'권유 없이 계약하는 경우',items:['상품 유형과 일반금융소비자 여부 등 적용 요건을 먼저 확인한다.','부적정 가능성이 있는 경우 경고·확인 절차를 검토한다.','계약 전 중요사항·비용·위험에 대한 설명과 기록 요건을 분리해 확인한다.']},explain:{title:'계약·설명 단계',items:['핵심설명서, 수수료·해지·손실가능성 등 중요사항을 이해 가능한 방식으로 전달한다.','설명자료·확인·계약서의 내용과 시점이 일관되는지 점검한다.','상품·고객상황이 바뀌면 이전 판단과 설명을 기계적으로 재사용하지 않는다.']}};document.querySelectorAll('[data-conduct]').forEach(button=>button.onclick=()=>{const m=modes[button.dataset.conduct];document.querySelectorAll('[data-conduct]').forEach(x=>x.classList.toggle('active',x===button));$('#conductOutcome').innerHTML=`<b>${m.title}</b><ol>${m.items.map(x=>`<li>${x}</li>`).join('')}</ol>`})}
function special(s){if(s==='01_economics')return `<section class="tool-panel"><h3>거시 해석 지도</h3><p>금리와 환율을 독립 변수로 보지 말고, 성장·물가·정책·위험선호의 결과로 연결합니다.</p><div class="formula-board"><div><b>국민소득</b><code>Y = C + I + G + (X − M)</code></div><div><b>실질금리 근사</b><code>r ≈ i − πᵉ</code></div><div><b>채권 1차 효과</b><code>ΔP/P ≈ −Dₘₒd × Δy</code></div></div><div class="quiz" data-answer="b"><button data-q="a">물가상승은 언제나 수요 과열이다</button><button data-q="b">충격의 원인을 수요·공급으로 분해한다</button><button data-q="c">환율은 수출입만으로 결정된다</button></div></section>${renderMacroLab()}`;if(s==='02_finance')return `<section class="tool-panel"><h3>채권 가격 민감도</h3><p>수정듀레이션 기반 1차 근사입니다. 큰 금리변화에서는 볼록성·현금흐름 재투자·스프레드를 별도로 고려하세요.</p><div class="calculator"><label>수정듀레이션<input id="duration" type="number" value="5" step="0.1"></label><label>금리 변화(bp)<input id="bps" type="number" value="25" step="1"></label><label>보유금액(원)<input id="principal" type="number" value="10000000" step="100000"></label><div class="result-box"><span>추정 가격 변동</span><strong id="bondResult">-</strong></div></div></section>${renderDcfLab()}`;if(s==='03_planning')return `<section class="tool-panel"><h3>세후 복리 수익률 비교</h3><p>교육용 단순 계산입니다. 실제 과세는 금융상품·계좌·손익통산·보유기간·개인별 요건에 따라 달라집니다.</p><div class="calculator"><label>원금(원)<input id="taxPrincipal" type="number" value="10000000" step="100000"></label><label>연 수익률(%)<input id="returnRate" type="number" value="6" step="0.1"></label><label>가정 세율(%)<input id="taxRate" type="number" value="15.4" step="0.1"></label><label>기간(년)<input id="years" type="number" value="3" min="1" step="1"></label><div class="result-box"><span>세후 추정 평가액</span><strong id="taxResult">-</strong></div></div></section>${renderCashflowLab()}`;return `<section class="tool-panel"><h3>금융상품 권유 전 점검</h3><p>아래 세 요소가 모두 확인되어야 권유 프로세스가 완결됩니다.</p><div class="formula-board"><div><b>고객 적합성</b><code>목적 · 재산 · 경험 · 위험선호</code></div><div><b>상품 이해</b><code>위험 · 비용 · 손실 가능성</code></div><div><b>기록과 설명</b><code>설명의 근거 · 확인 · 보존</code></div></div><div class="quiz" data-answer="c"><button data-q="a">수익 가능성만 설명하면 충분하다</button><button data-q="b">고객이 서명하면 설명의무는 사라진다</button><button data-q="c">상품과 고객 특성의 적합성을 먼저 확인한다</button></div></section>${renderConductLab()}`}
function bindTools(s){document.querySelectorAll('.quiz button').forEach(b=>b.onclick=()=>{const q=b.closest('.quiz');q.querySelectorAll('button').forEach(x=>x.className=x.dataset.q===q.dataset.answer?'correct':x===b?'wrong':'');});if(s==='01_economics')bindMacroLab();if(s==='02_finance'){const bond=()=>{const d=+$('#duration').value||0,b=(+$('#bps').value||0)/10000,p=+$('#principal').value||0,change=-d*b;$('#bondResult').textContent=`${change>=0?'+':''}${(change*100).toFixed(2)}% · ${won(p*change)}원`};['duration','bps','principal'].forEach(id=>$('#'+id).oninput=bond);bond();bindDcfLab()}if(s==='03_planning'){const tax=()=>{const p=+$('#taxPrincipal').value||0,r=(+$('#returnRate').value||0)/100,t=(+$('#taxRate').value||0)/100,y=+$('#years').value||0;$('#taxResult').textContent=`${won(p*Math.pow(1+r*(1-t),y))}원`};['taxPrincipal','returnRate','taxRate','years'].forEach(id=>$('#'+id).oninput=tax);tax();bindBufferLab()}if(s==='04_law')bindConductLab()}
async function loadMarket(){const node=$('#kospi'),time=$('#marketTime');if(!node)return;try{const tx=await fetch('https://stooq.com/q/l/?s=%5Ekospi&f=sd2t2c&e=csv').then(r=>r.text()),row=tx.trim().split(/\r?\n/)[1].split(',');const val=Number(row.at(-1));if(!Number.isFinite(val))throw Error();node.textContent='KOSPI '+won(val);node.className='live-value live-up';if(time)time.textContent=`Stooq · ${row[1]} ${row[2]} 기준`; }catch{node.textContent='KOSPI 시세 확인';node.className='live-value';if(time)time.innerHTML='<a href="https://global.krx.co.kr" target="_blank" rel="noreferrer">KRX에서 확인 ↗</a>'}}
const glossaryExtras=[
  {group:'경제',term:'실질금리',definition:'명목금리에서 기대인플레이션을 차감해 구매력 기준의 자금비용을 보는 근사치다.',cue:'명목금리보다 자금의 실질 부담이 어떻게 바뀌는지 확인'},
  {group:'금융',term:'WACC',definition:'타인자본비용과 자기자본비용을 자본구성 비중으로 가중평균한 기업의 할인율 기준이다.',cue:'FCFF의 위험과 할인율이 일관되는지 점검'},
  {group:'금융',term:'FCFF',definition:'기업이 영업활동과 필요한 재투자 후 채권자와 주주 모두에게 제공할 수 있는 잉여현금흐름이다.',cue:'EBIT가 아니라 세후영업이익·재투자까지 확인'},
  {group:'금융',term:'ROIC',definition:'투하자본 대비 세후영업이익의 수익성으로, 자본효율과 가치창출을 판단하는 지표다.',cue:'ROIC와 WACC의 차이가 가치창출 스프레드'},
  {group:'재무설계',term:'DSR',definition:'연간 소득 대비 모든 대출의 연간 원리금상환액 비율로, 상환여력을 판단하는 지표다.',cue:'대출 가능액이 아니라 월 현금흐름 부담으로 해석'},
  {group:'재무설계',term:'세후수익률',definition:'세금·수수료·비용을 차감한 뒤 실제로 남는 투자수익률이다.',cue:'상품 비교는 세전 명목수익률만으로 하지 않음'},
  {group:'법률',term:'적합성 원칙',definition:'금융상품을 권유할 때 고객의 정보와 상품 위험을 비교해 적합성을 판단하도록 하는 판매 규율이다.',cue:'권유 전 고객정보·상품위험·판단근거의 순서'},
  {group:'법률',term:'적정성 원칙',definition:'권유 없이 계약하려는 경우에도 부적정 가능성이 있는 상품에 대해 경고·확인 절차를 요구하는 규율이다.',cue:'적합성과 적용 장면이 같지 않음을 구분'},
  {group:'법률',term:'설명의무',definition:'일반금융소비자가 중요사항·위험·비용·손실 가능성을 이해할 수 있도록 설명하도록 하는 의무다.',cue:'설명 내용뿐 아니라 설명·확인의 기록까지 점검'}
];
function parseGlossary(markdown){let group='기타',entries=[];markdown.split(/\r?\n/).forEach(line=>{const heading=line.match(/^##\s+(.+)/);if(heading){group=heading[1].trim();return}const term=line.match(/^([^:#][^:]{1,80})\s*:\s+(.+)/);if(term)entries.push({group,term:term[1].trim(),definition:term[2].trim(),cue:''})});const seen=new Set(entries.map(entry=>entry.term.toLowerCase()));glossaryExtras.forEach(entry=>{if(!seen.has(entry.term.toLowerCase()))entries.push(entry)});return entries}
function glossaryCard(entry){return `<details class="glossary-card"><summary><span class="glossary-group">${entry.group}</span><b>${entry.term}</b><i>+</i></summary><div><p>${entry.definition}</p>${entry.cue?`<small><strong>학습 포인트</strong>${entry.cue}</small>`:''}</div></details>`}
function renderDictionary(){const chapter=guide.chapters.find(item=>item.slug==='05_dictionary'),entries=parseGlossary(chapter.markdown),groups=['핵심','전체',...new Set(entries.map(entry=>entry.group))];const featured=['GDP','총수요 AD','총공급 AS','듀레이션','만기수익률 YTM','DCF','WACC','FCFF','ISA','IRP','세후수익률','적합성 원칙','적정성 원칙','설명의무','미공개중요정보 이용'];const paint=()=>{const query=$('#glossarySearch').value.trim().toLowerCase(),active=$('#glossaryFilters .active')?.dataset.group||'핵심';let filtered=entries.filter(entry=>{const matches=!query||`${entry.term} ${entry.definition} ${entry.group}`.toLowerCase().includes(query);const category=active==='전체'||(active==='핵심'?featured.includes(entry.term):entry.group===active);return matches&&category});$('#glossaryCount').textContent=`${filtered.length}개 용어`;$('#glossaryGrid').innerHTML=filtered.length?filtered.map(glossaryCard).join(''):'<p class="glossary-empty">검색 조건에 맞는 용어가 없습니다.</p>'};$('#app').innerHTML=`<div class="page glossary-page"><header class="glossary-head"><div><p class="eyebrow">REFERENCE DESK</p><h1>용어 사전</h1><p>정의만 외우지 않고, 어느 분야에서 어떤 질문과 함께 쓰이는지 빠르게 복습합니다.</p></div><div class="glossary-search"><label for="glossarySearch">용어 검색</label><input id="glossarySearch" autocomplete="off" placeholder="예: 듀레이션, 적합성, GDP"><span>⌕</span></div></header><section class="glossary-toolbar"><div id="glossaryFilters" class="glossary-filters">${groups.map((group,index)=>`<button type="button" class="${index===0?'active':''}" data-group="${group}">${group}</button>`).join('')}</div><strong id="glossaryCount"></strong></section><section class="glossary-guide"><b>읽는 법</b><span>카드를 열어 정의와 학습 포인트를 확인하세요. 제도·세율·법령은 해당 분야의 공식 출처에서 시행일을 재확인합니다.</span><a href="content/expert-source-register.md" target="_blank">보강 출처 등록부 ↗</a></section><section id="glossaryGrid" class="glossary-grid"></section></div>`;$('#glossarySearch').addEventListener('input',paint);document.querySelectorAll('#glossaryFilters button').forEach(button=>button.onclick=()=>{document.querySelectorAll('#glossaryFilters button').forEach(item=>item.classList.toggle('active',item===button));paint()});paint()}
function bindGlobal(){document.addEventListener('click',e=>{const b=e.target.closest('[data-view]');if(b)go(b.dataset.view)});$('#homeButton').onclick=()=>go('home');$('#searchButton').onclick=()=>{$('#searchDialog').showModal();$('#termSearch').focus();search('')};$('#termSearch').oninput=e=>search(e.target.value)}
function search(q){const terms=[...guide.chapters].flatMap(c=>{const d=new DOMParser().parseFromString(c.html,'text/html');return [...d.querySelectorAll('h2,h3,h4,h5')].map(h=>({title:h.textContent.trim(),chapter:c.slug,text:(h.nextElementSibling?.textContent||'').slice(0,100)}))}).filter(x=>!q||`${x.title} ${x.text}`.toLowerCase().includes(q.toLowerCase())).slice(0,20);$('#searchResults').innerHTML=terms.map(x=>`<button class="search-result" data-view="${x.chapter}"><b>${x.title}</b><span>${meta[x.chapter]?.name||'용어'} · ${x.text}</span></button>`).join('')||'<p>일치하는 항목이 없습니다.</p>'}
boot().catch(()=>{$('#app').innerHTML='<div class="page"><p>콘텐츠를 불러오지 못했습니다. 새로고침 후 다시 시도하세요.</p></div>'});
